import { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Menu, X, Home, Building2, Calculator, Phone, LogIn, User, LogOut, Shield, ChevronDown } from 'lucide-react';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout, isAuthenticated } = useAuth();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/');
    setIsDropdownOpen(false);
  };

  const navLinks = [
    { name: 'Home', path: '/', icon: Home },
    { name: 'Properties', path: '/projects', icon: Building2 },
    { name: 'EMI', path: '/emi-calculator', icon: Calculator },
    { name: 'Contact', path: '/contact', icon: Phone },
  ];

  const isAdmin = user?.email === 'admin@swabhagya.com' || user?.role === 'admin';

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-500 ${isScrolled ? 'navbar-glass py-3' : 'bg-transparent py-5'}`}>
      <div className="container-custom">
        <div className="flex justify-between items-center">
          {/* Premium Logo */}
          <Link to="/" className="relative group">
            <div className="flex items-center gap-2">
              <div className="w-12 h-12 relative">
                <div className="absolute inset-0 bg-gradient-to-br from-[#c8a45e] to-[#bf953f] rounded-full blur-sm group-hover:blur-md transition-all duration-300"></div>
                <div className="relative w-full h-full bg-gradient-to-br from-[#c8a45e] to-[#bf953f] rounded-full flex items-center justify-center">
                  <span className="text-black font-bold text-xl">S</span>
                </div>
              </div>
              <div>
                <span className="text-white font-light text-xs tracking-[0.3em] block">LUXURY</span>
                <span className="text-white font-bold text-2xl tracking-wide">SWABHAGYA</span>
              </div>
            </div>
          </Link>
          
          {/* Desktop Menu */}
          <div className="hidden lg:flex items-center gap-12">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`relative font-medium text-sm uppercase tracking-wider transition-all duration-300 ${
                  location.pathname === link.path 
                    ? 'text-[#c8a45e]' 
                    : 'text-white/80 hover:text-[#c8a45e]'
                }`}
              >
                {link.name}
                {location.pathname === link.path && (
                  <span className="absolute -bottom-1 left-0 w-full h-0.5 bg-[#c8a45e]"></span>
                )}
              </Link>
            ))}
            
            <Link
              to="/admin/login"
              className="flex items-center gap-2 text-white/70 hover:text-[#c8a45e] transition text-sm uppercase tracking-wider"
            >
              <Shield size={16} />
              Admin
            </Link>
            
            <a 
              href="https://wa.me/919272560005?text=Hi%20Swabhagya%20Realty%2C%20I'm%20interested%20in%20your%20properties"
              target="_blank"
              rel="noopener noreferrer"
              className="btn-premium"
            >
              Enquire Now
            </a>
            
            {isAuthenticated ? (
              <div className="relative">
                <button
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="flex items-center gap-2 text-white hover:text-[#c8a45e] transition"
                >
                  <span className="w-8 h-8 rounded-full bg-[#c8a45e]/20 flex items-center justify-center">
                    <User size={16} className="text-[#c8a45e]" />
                  </span>
                  <span className="text-sm">{user?.name?.split(' ')[0]}</span>
                  <ChevronDown size={14} />
                </button>
                
                {isDropdownOpen && (
                  <div className="absolute right-0 mt-3 w-52 bg-white/95 backdrop-blur-lg rounded-lg shadow-2xl py-2 z-50 border border-[#c8a45e]/20">
                    <Link
                      to="/dashboard"
                      onClick={() => setIsDropdownOpen(false)}
                      className="flex items-center gap-3 px-4 py-2.5 text-gray-700 hover:bg-[#c8a45e]/10 transition"
                    >
                      <User size={16} /> Dashboard
                    </Link>
                    {isAdmin && (
                      <Link
                        to="/admin/dashboard"
                        onClick={() => setIsDropdownOpen(false)}
                        className="flex items-center gap-3 px-4 py-2.5 text-gray-700 hover:bg-[#c8a45e]/10 transition"
                      >
                        <Shield size={16} /> Admin Panel
                      </Link>
                    )}
                    <hr className="my-1" />
                    <button
                      onClick={handleLogout}
                      className="flex items-center gap-3 w-full text-left px-4 py-2.5 text-red-600 hover:bg-red-50 transition"
                    >
                      <LogOut size={16} /> Logout
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <Link
                to="/login"
                className="btn-outline-premium"
              >
                Login / Signup
              </Link>
            )}
          </div>
          
          <button 
            className="lg:hidden text-white"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
        
        {/* Mobile Menu */}
        {isMobileMenuOpen && (
          <div className="lg:hidden mt-4 bg-black/90 backdrop-blur-lg rounded-2xl p-6 border border-[#c8a45e]/20">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c8a45e] transition"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                <link.icon size={18} />
                {link.name}
              </Link>
            ))}
            
            <Link
              to="/admin/login"
              className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c8a45e] transition"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              <Shield size={18} /> Admin
            </Link>
            
            <a 
              href="https://wa.me/919272560005?text=Hi%20Swabhagya%20Realty"
              target="_blank"
              rel="noopener noreferrer"
              className="block w-full btn-premium text-center mt-4"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              Enquire Now
            </a>
            
            <div className="border-t border-white/20 pt-4 mt-4">
              {isAuthenticated ? (
                <>
                  <Link
                    to="/dashboard"
                    className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c8a45e]"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <User size={18} /> Dashboard
                  </Link>
                  {isAdmin && (
                    <Link
                      to="/admin/dashboard"
                      className="flex items-center gap-3 py-3 text-white/80 hover:text-[#c8a45e]"
                      onClick={() => setIsMobileMenuOpen(false)}
                    >
                      <Shield size={18} /> Admin Panel
                    </Link>
                  )}
                  <button
                    onClick={handleLogout}
                    className="flex items-center gap-3 py-3 text-red-400 hover:text-red-300 w-full"
                  >
                    <LogOut size={18} /> Logout
                  </button>
                </>
              ) : (
                <Link
                  to="/login"
                  className="flex items-center gap-3 py-3 text-[#c8a45e] font-semibold"
                  onClick={() => setIsMobileMenuOpen(false)}
                >
                  <LogIn size={18} /> Login / Signup
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
